INSERT INTO `blogs` VALUES (1,'iPhone 17 Series chính thức ra mắt: Những điểm nâng cấp đáng giá nhất','iphone-17-series-chinh-thuc-ra-mat','Apple vừa chính thức công bố dòng iPhone 17 Series tại sự kiện \"Glowtime\" với 4 mẫu: iPhone 17, iPhone 17 Plus, iPhone 17 Pro và iPhone 17 Pro Max. Đây là thế hệ iPhone đầu tiên tích hợp đầy đủ Apple Intelligence trên tất cả các mẫu, không chỉ riêng dòng Pro.\n\nĐiểm nổi bật nhất là chip Apple A18 và A18 Pro — mạnh hơn 30% so với A17 Pro trong khi tiêu thụ điện năng ít hơn 20%. Camera hệ thống được nâng cấp toàn diện: cảm biến 48MP thế hệ mới với khẩu độ f/1.6 trên iPhone 17 thường và 50MP periscope telephoto trên Pro Max.\n\nGiá khởi điểm tại Việt Nam từ 27.990.000đ cho iPhone 17 128GB, và lên đến 59.990.000đ cho iPhone 17 Pro Max 1TB.','https://cdn.shop.vn/blogs/iphone17-launch-thumb.jpg',1,1,1,1,1,'2025-04-01 10:00:00.000000','2025-04-01 10:00:00.000000'),(2,'Samsung Galaxy S25 Series: Snapdragon 8 Elite và Galaxy AI nâng tầm trải nghiệm','samsung-galaxy-s25-series-review','Samsung Galaxy S25 Series ra mắt đầu năm 2025 với chip Snapdragon 8 Elite độc quyền từ Qualcomm — lần đầu tiên tất cả các thị trường đều dùng chung chip thay vì tách Exynos/Snapdragon theo khu vực.\n\nGalaxy AI phiên bản 2025 hỗ trợ tiếng Việt tốt hơn nhiều, với các tính năng nổi bật: Chat Assist dịch và soạn thảo tin nhắn thông minh, Note Assist tóm tắt cuộc họp, Live Translate phiên dịch realtime. S25 Ultra giữ nguyên bút S Pen nhưng nâng cấp độ nhạy lên 4096 cấp độ.\n\nGiá bán tại TechShop từ 22.990.000đ cho Galaxy S25 và 35.990.000đ cho Galaxy S25 Ultra.','https://cdn.shop.vn/blogs/samsung-s25-review-thumb.jpg',1,1,2,1,1,'2025-02-05 09:00:00.000000','2025-02-05 09:00:00.000000'),(3,'MacBook Pro M4 vs MacBook Air M3: Nên chọn máy nào?','macbook-pro-m4-vs-macbook-air-m3','Câu hỏi muôn thuở của người dùng Apple: mua MacBook Air hay MacBook Pro? Bài viết này sẽ so sánh chi tiết MacBook Air M3 (28.990.000đ) và MacBook Pro 14\" M4 (52.990.000đ) để giúp bạn đưa ra quyết định đúng đắn.\n\n**Hiệu năng:** M4 Pro trong MacBook Pro mạnh hơn M3 khoảng 40-50% về đa luồng, phù hợp với video editing 4K-8K, 3D render, compile code nặng. M3 trong Air đủ mạnh cho 95% tác vụ thông thường.\n\n**Màn hình:** Pro có ProMotion 120Hz và XDR, Air chỉ có 60Hz Liquid Retina. Sự khác biệt rõ rệt khi xem video và cuộn trang web.\n\n**Tản nhiệt:** Air không quạt nên giới hạn hiệu năng khi tác vụ kéo dài. Pro có hệ thống quạt kép duy trì hiệu năng đỉnh liên tục.\n\n**Kết luận:** Sinh viên, dân văn phòng → MacBook Air M3. Creative professional → MacBook Pro M4.','https://cdn.shop.vn/blogs/macbook-compare-thumb.jpg',1,0,NULL,1,1,'2025-03-15 09:00:00.000000','2025-03-15 09:00:00.000000'),(4,'Top 5 điện thoại Android đáng mua nhất tầm 10-15 triệu năm 2025','top-5-dien-thoai-android-tam-10-15-trieu-2025','Phân khúc tầm trung 10-15 triệu đang cực kỳ cạnh tranh với nhiều lựa chọn hấp dẫn. Dưới đây là top 5 điện thoại Android đáng mua nhất tại TechShop:\n\n1. **Samsung Galaxy A55 5G (10.990.000đ)** — Super AMOLED 120Hz, camera OIS 50MP, thiết kế premium\n2. **Redmi Note 14 Pro+ 5G (11.990.000đ)** — Camera 200MP, sạc 120W, pin 6000mAh\n3. **OPPO Reno 12 Pro 5G (13.990.000đ)** — Thiết kế mỏng nhất, AI camera, SUPERVOOC 80W\n4. **Xiaomi 15 (19.990.000đ)** — Camera Leica, Snap 8 Elite, màn 144Hz\n5. **Samsung Galaxy S25 (22.990.000đ)** — Snap 8 Elite, Galaxy AI đầy đủ\n\nTùy nhu cầu ưu tiên về camera, pin hay hiệu năng, mỗi máy có thế mạnh riêng. Đến TechShop trải nghiệm trực tiếp để có lựa chọn tốt nhất!','https://cdn.shop.vn/blogs/top5-android-thumb.jpg',1,0,NULL,1,1,'2025-04-20 09:00:00.000000','2025-04-20 09:00:00.000000'),(5,'Xiaomi 15 ra mắt tại Việt Nam: Camera Leica, Snapdragon 8 Elite giá từ 19.990.000đ','xiaomi-15-ra-mat-viet-nam','Xiaomi 15 chính thức có mặt tại Việt Nam với mức giá khởi điểm 19.990.000đ cho bản 12GB/256GB — mức giá ấn tượng cho flagship với chip Snapdragon 8 Elite.\n\nHệ thống camera Leica Triple Camera gồm camera chính 50MP Light Fusion 900, camera tele 50MP 2.6x và camera góc rộng 50MP — cả ba đều 50MP là điểm khác biệt lớn so với đối thủ. Màn hình AMOLED 6.36 inch với tần số quét 144Hz, độ sáng đỉnh 3200 nits, cực kỳ sắc nét dưới ánh nắng.\n\nPin 5400mAh sạc có dây 90W đầy trong 37 phút, sạc không dây 50W và sạc ngược 10W. Thiết kế mỏng 7.98mm, khung titan nguyên khối cao cấp.','https://cdn.shop.vn/blogs/xiaomi15-launch-thumb.jpg',1,1,3,1,1,'2025-03-05 09:00:00.000000','2025-03-05 09:00:00.000000'),(6,'SALE THÁNG 5: Giảm đến 20% tất cả iPhone và MacBook','sale-thang-5-giam-20-iphone-macbook','Nhân dịp kỷ niệm 5 năm thành lập TechShop, chúng tôi tung chương trình khuyến mãi cực khủng:\n\n? **ĐIỆN THOẠI:**\n- iPhone 16 series: Giảm 1-2 triệu\n- iPhone 17 series: Giảm đến 3 triệu\n- Samsung Galaxy S25 series: Giảm đến 2 triệu\n\n? **LAPTOP:**\n- MacBook Air M3: Giảm 2 triệu\n- MacBook Pro M4: Giảm 3 triệu\n- Laptop gaming ASUS ROG: Giảm đến 4 triệu\n\n? **QUÀ TẶNG KÈM:**\n- Ốp lưng chính hãng\n- Cường lực full màn hình\n- Gói bảo hành mở rộng 1 năm\n\n⏰ **Thời gian:** 01/05 - 31/05/2025\n\nSử dụng mã **SALE200K** để giảm thêm 200.000đ cho đơn từ 2 triệu!','https://cdn.shop.vn/blogs/sale-thang5-thumb.jpg',1,1,4,2,1,'2025-05-01 07:00:00.000000','2025-05-01 07:00:00.000000'),(7,'Ưu đãi cuối tuần: Mua MacBook tặng AirPods Pro 2 trị giá 6.390.000đ','uu-dai-cuoi-tuan-mua-macbook-tang-airpods-pro','Chỉ trong 2 ngày cuối tuần (10-11/05/2025), khi mua bất kỳ MacBook nào tại TechShop, bạn sẽ nhận ngay AirPods Pro 2 trị giá 6.390.000đ hoàn toàn MIỄN PHÍ.\n\n**Điều kiện áp dụng:**\n- Mua tại cửa hàng hoặc đặt online trong thời gian khuyến mãi\n- Áp dụng cho tất cả MacBook Air M3 và MacBook Pro M4\n- Mỗi khách hàng nhận tối đa 1 phần quà\n- Không kết hợp với các chương trình khuyến mãi khác\n\n**Bonus thêm:** Thanh toán qua VNPay hoặc MoMo được hoàn tiền thêm 500.000đ!\n\nĐừng bỏ lỡ cơ hội sở hữu combo MacBook + AirPods Pro 2 với mức giá tốt nhất trong năm. Số lượng quà tặng có hạn!','https://cdn.shop.vn/blogs/uu-dai-macbook-airpods-thumb.jpg',1,0,NULL,2,1,'2025-05-08 08:00:00.000000','2025-05-08 08:00:00.000000'),(8,'Flash Sale 24h: Samsung Galaxy S25 Ultra chỉ còn 33.990.000đ','flash-sale-samsung-s25-ultra-33990000','Cơ hội vàng cho fan Samsung! Chỉ trong 24 giờ ngày 15/04/2025, Samsung Galaxy S25 Ultra 256GB giảm sốc xuống còn **33.990.000đ** (tiết kiệm 2 triệu so với giá niêm yết).\n\n**Tại sao S25 Ultra đáng mua?**\n- Bút S Pen tích hợp: vẽ, viết tay, ký tên chuyên nghiệp\n- Camera 200MP: zoom 100x vẫn rõ nét\n- Galaxy AI: phiên dịch realtime, tóm tắt cuộc họp\n- Snapdragon 8 Elite: hiệu năng AI số 1 Android\n- Màn hình 6.9 inch QHD+ 120Hz đẹp nhất thị trường\n\n**Kèm theo:**\n- Ốp lưng Samsung chính hãng\n- Dán cường lực màn hình\n- Bảo hành 2 năm chính hãng Samsung\n\n⚡ Chỉ còn 50 suất. Đặt ngay để không hối tiếc!','https://cdn.shop.vn/blogs/flash-sale-s25ultra-thumb.jpg',1,0,NULL,2,1,'2025-04-14 20:00:00.000000','2025-04-14 20:00:00.000000'),(9,'Mùa hè mát lạnh: Giảm đến 15% máy lạnh Daikin, tặng lắp đặt miễn phí','mua-he-mat-lanh-giam-15-may-lanh-daikin','Chào đón mùa hè 2025, TechShop hợp tác cùng Daikin tung chương trình ưu đãi đặc biệt:\n\n❄️ **GIẢM 15%** toàn bộ máy lạnh Daikin Inverter\n? **TẶNG** lắp đặt và vệ sinh miễn phí (trị giá 500.000đ)\n? **MIỄN PHÍ** vận chuyển toàn quốc\n? **Trả góp 0%** lãi suất trong 12 tháng\n\nMáy lạnh Daikin Inverter tiết kiệm điện đến 60% so với máy thường, phù hợp phòng ngủ, phòng khách từ 15-40m2.\n\n**Hotline tư vấn:** 1800-1234 (miễn phí, 8h-22h hàng ngày)\n\n**Thời gian:** 01/05 - 30/06/2025','https://cdn.shop.vn/blogs/may-lanh-daikin-sale-thumb.jpg',1,0,NULL,2,1,'2025-05-01 08:00:00.000000','2025-05-01 08:00:00.000000'),(10,'Siêu Sale 30/4 - 1/5: Hàng trăm sản phẩm giảm giá cực sốc','sieu-sale-30-4-1-5-hang-tram-san-pham-giam-gia','Nghỉ lễ 30/4 - 1/5 năm nay cùng TechShop mua sắm thả ga! Chương trình Siêu Sale kéo dài 4 ngày từ 28/04 đến 01/05/2025 với hàng nghìn sản phẩm giảm giá.\n\n? **ĐIỆN THOẠI** — Giảm đến 25%\n- iPhone 16 series giảm đến 2 triệu\n- Samsung Galaxy A55 5G giảm 1.5 triệu\n- Redmi Note 14 Pro+ giảm 1 triệu\n\n? **LAPTOP** — Giảm đến 20%\n- ASUS ROG G14 2024 giảm 3 triệu\n- Dell XPS 13 Plus giảm 4 triệu\n- Lenovo ThinkPad X1 Carbon giảm 5 triệu\n\n? **PHỤ KIỆN** — Giảm đến 30%\n- AirPods Pro 2 giảm 500.000đ\n- Ốp lưng, cường lực giảm 30-50%\n\n? **Voucher đặc biệt:** Nhập **VIP20** giảm thêm 20% tối đa 1 triệu!\n\nSố lượng có hạn, nhanh tay kẻo lỡ!','https://cdn.shop.vn/blogs/sieu-sale-304-thumb.jpg',1,1,5,2,1,'2025-04-27 08:00:00.000000','2025-04-27 08:00:00.000000');
