INSERT INTO `product_reviews` VALUES (6,8,2,5,'ProMotion 120Hz mượt không tưởng, camera telephoto 5x chụp zoom cực nét. Chip A18 Pro handle mọi tác vụ nặng không nóng máy. Đỉnh của đỉnh!','ACTIVE','2025-03-15 14:00:00.000000','2025-03-15 14:00:00.000000'),(7,3,2,5,'Đây là chiếc iPhone đáng mua nhất trong dòng iPhone 17. Cân bằng tốt giữa kích thước, hiệu năng và camera. Sạc MagSafe 25W rất tiện.','ACTIVE','2025-04-01 09:00:00.000000','2025-04-01 09:00:00.000000'),(8,16,2,5,'Khung titanium cứng cáp, nhẹ hơn inox nhiều. Camera chụp video Dolby Vision 4K120fps rất ấn tượng. Pin tốt hơn Pro trước.','ACTIVE','2025-04-15 10:00:00.000000','2025-04-15 10:00:00.000000'),(9,20,2,4,'Máy đẹp, hiệu năng vượt trội nhưng giá hơi cao. Nếu không cần camera Pro thì chọn iPhone 17 thường sẽ tiết kiệm hơn nhiều.','ACTIVE','2025-04-20 11:00:00.000000','2025-04-20 11:00:00.000000'),(10,5,3,5,'Màn hình 6.9 inch cực to, xem phim rất đã mắt. Pin 4685mAh dùng cả ngày thoải mái. Camera periscope 5x zoom xa mà vẫn cực nét. Flagship xứng đáng!','ACTIVE','2025-03-05 15:00:00.000000','2025-03-05 15:00:00.000000'),(11,12,3,5,'Đây là điện thoại tốt nhất tôi từng dùng. Mọi thứ đều hoàn hảo từ màn hình, camera, pin đến hiệu năng. Giá cao nhưng hoàn toàn xứng đáng.','ACTIVE','2025-03-20 09:00:00.000000','2025-03-20 09:00:00.000000'),(12,2,3,5,'Mua cho ba dùng thay iPhone 13 Pro Max, ba khen màn hình to rõ, camera đẹp, pin lâu. Giao hàng nhanh, máy nguyên seal. 5 sao!','ACTIVE','2025-04-05 10:00:00.000000','2025-04-05 10:00:00.000000'),(13,17,3,4,'Máy quá to, tay nhỏ cầm hơi khó. Nhưng hiệu năng và camera thì không có gì chê. Chỉ khuyên người tay nhỏ nên cân nhắc Pro thường.','ACTIVE','2025-04-18 11:00:00.000000','2025-04-18 11:00:00.000000'),(14,9,3,5,'Camera hệ thống Pro cực kỳ linh hoạt: góc rộng, tele, macro đều xuất sắc. Chế độ chụp đêm cải thiện nhiều so với thế hệ trước.','ACTIVE','2025-05-01 09:00:00.000000','2025-05-01 09:00:00.000000'),(19,7,5,4,'Màn hình 6.7 inch xem phim rất thích. Pin là điểm nổi bật nhất dòng 16, dùng 2 ngày không cần sạc nếu dùng bình thường.','ACTIVE','2025-04-10 09:00:00.000000','2025-04-10 09:00:00.000000'),(20,15,5,5,'Máy to nhưng mỏng và nhẹ hơn tưởng. Camera góc rộng 48MP chụp thiên nhiên rất đẹp. Hài lòng với lựa chọn này.','ACTIVE','2025-04-20 14:00:00.000000','2025-04-20 14:00:00.000000'),(21,20,5,4,'Giá hợp lý so với Pro Max, camera không bằng nhưng vẫn rất tốt. Màn hình sáng rõ ngoài nắng. Sẽ giới thiệu cho bạn bè.','ACTIVE','2025-05-05 10:00:00.000000','2025-05-05 10:00:00.000000'),(22,6,6,5,'Snap 8 Elite quá mượt, chơi game PUBG 90fps không giật. Màn hình AMOLED sáng đẹp, Galaxy AI hỗ trợ tiếng Việt tốt hơn iPhone nhiều!','ACTIVE','2025-03-10 09:00:00.000000','2025-03-10 09:00:00.000000'),(23,11,6,4,'Thiết kế nhỏ gọn, cầm thoải mái hơn Ultra. Camera 50MP chụp đẹp, màu sắc trung thực. Pin 4000mAh hơi nhỏ nhưng Snap 8 Elite tiết kiệm điện tốt.','ACTIVE','2025-03-25 10:00:00.000000','2025-03-25 10:00:00.000000'),(24,16,6,5,'Mua thay Galaxy S23, cải thiện rõ rệt về hiệu năng và camera. Sạc nhanh 45W pin đầy chưa đến 1 tiếng. Rất hài lòng!','ACTIVE','2025-04-10 11:00:00.000000','2025-04-10 11:00:00.000000'),(25,2,6,4,'Màn hình nhỏ hơn tưởng nhưng cầm vừa tay. Camera AI xóa phông đẹp. Giá hơi cao so với Xiaomi cùng chip nhưng hệ sinh thái Samsung tốt hơn.','ACTIVE','2025-04-20 09:00:00.000000','2025-04-20 09:00:00.000000'),(26,19,6,5,'Galaxy AI tóm tắt văn bản, phiên dịch realtime cực hay. Hiệu năng gaming xuất sắc. Đây là flagship Android đáng mua nhất tầm 22 triệu.','ACTIVE','2025-05-05 14:00:00.000000','2025-05-05 14:00:00.000000'),(27,5,7,5,'S Pen mượt hơn hẳn S24 Ultra, viết tay và vẽ rất thích. Camera 200MP chụp zoom xa cực nét. Hiệu năng đỉnh, xứng đáng giá premium.','ACTIVE','2025-04-01 09:00:00.000000','2025-04-01 09:00:00.000000'),(28,13,7,5,'Màn hình 6.9 inch QHD+ xem video cực đỉnh. AI tóm tắt cuộc họp, dịch thuật realtime rất hữu ích cho công việc. Pin 5000mAh dùng nguyên ngày dễ dàng.','ACTIVE','2025-04-15 10:00:00.000000','2025-04-15 10:00:00.000000'),(29,2,7,4,'Máy quá to, khó dùng một tay. Nhưng S Pen và camera là điểm cộng lớn. Nếu cần S Pen thì không có lựa chọn nào tốt hơn.','ACTIVE','2025-04-25 11:00:00.000000','2025-04-25 11:00:00.000000'),(30,7,7,5,'Dùng Ultra thay thế máy tính bảng luôn, màn hình to làm việc thoải mái. DeX mode kết nối màn hình rời rất tiện. Đầu tư xứng đáng!','ACTIVE','2025-05-08 09:00:00.000000','2025-05-08 09:00:00.000000'),(31,10,8,4,'Tầm giá 11 triệu mà có Super AMOLED 120Hz, camera OIS rất tốt. Thiết kế nhìn như flagship. Chip Exynos 1480 không phải mạnh nhất nhưng đủ dùng.','ACTIVE','2025-04-01 10:00:00.000000','2025-04-01 10:00:00.000000'),(32,15,8,5,'Camera OIS chụp đêm rõ hơn nhiều so với A35. Video quay mượt không rung. Sạc 45W pin đầy nhanh. Rất đáng mua tầm trung.','ACTIVE','2025-04-10 09:00:00.000000','2025-04-10 09:00:00.000000'),(33,20,8,4,'Máy đẹp, thiết kế sang. RAM 8GB dùng thoải mái không lag. Chỉ tiếc không có sạc trong hộp và không có jack 3.5mm.','ACTIVE','2025-04-20 11:00:00.000000','2025-04-20 11:00:00.000000'),(34,4,8,4,'Mua cho mẹ dùng, mẹ khen màn hình to đẹp, mượt. Giao hàng nhanh, máy nguyên seal. Samsung uy tín.','ACTIVE','2025-04-25 14:00:00.000000','2025-04-25 14:00:00.000000'),(35,9,8,5,'Đây là điện thoại tầm trung đáng mua nhất hiện tại. Màn hình Super AMOLED đẹp hơn OLED nhiều máy cùng giá. Camera chụp selfie đẹp.','ACTIVE','2025-05-02 09:00:00.000000','2025-05-02 09:00:00.000000'),(36,9,9,5,'Camera Leica chụp ảnh có màu sắc đặc trưng, chi tiết cao. Sạc 90W pin đầy 30 phút. Thiết kế mỏng nhẹ, màn hình 144Hz cực mượt. Rất đáng tiền!','ACTIVE','2025-04-01 09:00:00.000000','2025-04-01 09:00:00.000000'),(37,4,9,5,'Máy mạnh ngang S25 mà giá rẻ hơn 3 triệu. MIUI 16 cải thiện nhiều, ít bloatware. Camera tele 2x chụp portrait rất đẹp.','ACTIVE','2025-04-15 10:00:00.000000','2025-04-15 10:00:00.000000'),(38,18,9,4,'Hiệu năng rất tốt, game nặng cũng chạy mượt. Camera Leica đẹp nhưng màu hơi bão hòa. Pin 5400mAh dùng thoải mái cả ngày.','ACTIVE','2025-05-01 11:00:00.000000','2025-05-01 11:00:00.000000'),(39,10,10,5,'Camera 200MP chụp cực nét, xóa phông đẹp. Sạc 120W siêu nhanh, 15 phút đầy pin. Màn hình AMOLED 144Hz mượt mà. Vua tầm trung không ngoa!','ACTIVE','2025-04-05 09:00:00.000000','2025-04-05 09:00:00.000000'),(40,17,10,4,'Pin 6000mAh khủng, dùng 2 ngày không lo hết pin. Camera 200MP ấn tượng nhưng xử lý ảnh hơi lâu. Nhìn chung rất đáng tiền tầm 12 triệu.','ACTIVE','2025-04-20 10:00:00.000000','2025-04-20 10:00:00.000000'),(41,3,10,5,'Mua thay Note 12 Pro, cải thiện toàn diện. Màn hình cong đẹp, loa Stereo to rõ. Giá 12 triệu mà có camera 200MP và sạc 120W, quá hời!','ACTIVE','2025-05-05 09:00:00.000000','2025-05-05 09:00:00.000000'),(42,8,10,4,'Chụp ảnh đẹp, thiết kế sang. Chỉ hơi nặng 227g khi cầm lâu. MIUI 16 còn vài lỗi nhỏ nhưng nhìn chung ổn.','ACTIVE','2025-05-10 11:00:00.000000','2025-05-10 11:00:00.000000'),(43,2,11,5,'Hiệu năng M3 vượt trội mọi Intel cùng tầm giá. Không quạt nên tuyệt đối im lặng. Màn hình Liquid Retina sắc nét. Pin 18 giờ dùng cả ngày không lo.','ACTIVE','2025-02-15 09:00:00.000000','2025-02-15 09:00:00.000000'),(44,14,11,5,'Sinh viên IT mua làm code và design, M3 handle mọi thứ mượt mà. Máy nhẹ 1.24kg mang đi học thoải mái. Đây là laptop đáng mua nhất tầm 30 triệu.','ACTIVE','2025-03-10 10:00:00.000000','2025-03-10 10:00:00.000000'),(45,7,11,5,'Chuyển từ Windows sang MacOS, ban đầu hơi lạ nhưng quen rất nhanh. Hệ sinh thái Apple seamless với iPhone. Build quality tuyệt vời.','ACTIVE','2025-03-25 11:00:00.000000','2025-03-25 11:00:00.000000'),(46,19,11,4,'M3 mạnh nhưng chỉ 8GB RAM hơi ít nếu làm video editing nặng. Nên lên 16GB cho thoải mái. Nhìn chung vẫn là MacBook Air tốt nhất từ trước đến nay.','ACTIVE','2025-04-05 09:00:00.000000','2025-04-05 09:00:00.000000'),(47,11,11,5,'Sau 3 tháng dùng vẫn mượt như mới, pin vẫn giữ 95%. Không nóng kể cả khi render. Recommend mạnh cho ai cần laptop bền, mỏng nhẹ và mạnh.','ACTIVE','2025-05-10 14:00:00.000000','2025-05-10 14:00:00.000000'),(48,6,12,5,'Làm video edit 4K trên Final Cut Pro mượt không kịp. M4 Pro cải thiện đáng kể về Neural Engine. Màn hình XDR ProMotion 120Hz cực đẹp. Đáng tiền!','ACTIVE','2025-04-01 09:00:00.000000','2025-04-01 09:00:00.000000'),(49,12,12,5,'Dân làm đồ họa chuyên nghiệp cần máy này. Compile code siêu nhanh, Xcode build app iOS chỉ vài giây. Pin 22 giờ làm việc cả ngày không sạc.','ACTIVE','2025-04-15 10:00:00.000000','2025-04-15 10:00:00.000000'),(50,3,12,5,'Đầu tư hơn 50 triệu nhưng xứng đáng. M4 Pro xử lý 3D rendering nhanh hơn máy trạm Windows giá tương đương. Speaker 6 loa nghe nhạc tuyệt vời.','ACTIVE','2025-04-25 11:00:00.000000','2025-04-25 11:00:00.000000'),(51,20,12,4,'Tuyệt vời về hiệu năng nhưng giá khá cao. Nếu không làm nội dung nặng thì MacBook Air M3 là đủ. MBP M4 dành cho pro thực sự.','ACTIVE','2025-05-05 09:00:00.000000','2025-05-05 09:00:00.000000'),(52,13,13,5,'Màn hình OLED 4K đẹp không tưởng, thiết kế siêu mỏng cao cấp. Bàn phím haptic cảm giác lạ lúc đầu nhưng quen rất nhanh. Laptop Windows đẹp nhất hiện tại.','ACTIVE','2025-04-20 09:00:00.000000','2025-04-20 09:00:00.000000'),(53,4,13,4,'Build quality tuyệt vời, máy cứng cáp. OLED 4K rực rỡ nhưng tốn pin hơn. Chỉ có 2 cổng Thunderbolt nên cần hub nếu dùng nhiều thiết bị.','ACTIVE','2025-05-01 10:00:00.000000','2025-05-01 10:00:00.000000'),(54,17,13,4,'Laptop văn phòng hạng sang, mỏng nhẹ mang đi công tác rất tiện. Màn hình OLED sắc sảo. Tản nhiệt hơi ồn khi load nặng.','ACTIVE','2025-05-10 11:00:00.000000','2025-05-10 11:00:00.000000'),(55,6,14,5,'Gaming laptop mỏng nhất mà có RTX 4070! Màn hình OLED 165Hz cực mượt, màu sắc đẹp. Chơi game AAA max setting 60+ fps. Rất đáng mua cho game thủ di động.','ACTIVE','2025-03-10 09:00:00.000000','2025-03-10 09:00:00.000000'),(56,2,14,5,'Ryzen 9 8945HS kết hợp RTX 4070 quá mạnh. AniMe Matrix logo trước mặt máy rất cool. Bàn phím RGB per-key đẹp. Tản nhiệt tốt, không quá ồn.','ACTIVE','2025-03-25 10:00:00.000000','2025-03-25 10:00:00.000000'),(57,8,14,4,'Hiệu năng gaming xuất sắc, Cyberpunk 2077 Ultra 1080p được 80fps ổn định. Chỉ hơi tiếc màn hình 1600p hơi nhỏ với game thủ thích immersive.','ACTIVE','2025-04-10 11:00:00.000000','2025-04-10 11:00:00.000000'),(58,15,14,5,'Laptop gaming kiêm làm đồ họa tốt nhất tầm 43 triệu. OLED panel đẹp hơn IPS nhiều, màu sắc chuẩn cho Photoshop. Đa năng nhất phân khúc.','ACTIVE','2025-04-20 09:00:00.000000','2025-04-20 09:00:00.000000'),(59,18,14,5,'Mua 2 tháng dùng rất ổn, không có vấn đề gì. Hiệu năng như quảng cáo. ASUS Armory Crate quản lý profile tốt. Recommend mạnh!','ACTIVE','2025-05-08 10:00:00.000000','2025-05-08 10:00:00.000000'),(60,14,15,5,'Doanh nhân thì phải chọn ThinkPad. Nhẹ 1.12kg mà pin 15 giờ, cứng cáp vượt chuẩn MIL-SPEC. Bàn phím ThinkPad tốt nhất trên thị trường laptop.','ACTIVE','2025-03-15 09:00:00.000000','2025-03-15 09:00:00.000000'),(61,7,15,5,'RAM 32GB xử lý đa nhiệm mượt, có 20 tab Chrome + Slack + Zoom không giật. TrackPoint đỏ quen tay rất hiệu quả. Build quality đỉnh của Lenovo.','ACTIVE','2025-04-01 10:00:00.000000','2025-04-01 10:00:00.000000'),(62,19,15,4,'Hiệu năng tốt, pin trâu. Thiết kế hơi nhàm chán so với XPS hay MacBook nhưng bù lại độ bền và bàn phím thì vô đối. Phù hợp dân văn phòng.','ACTIVE','2025-04-20 11:00:00.000000','2025-04-20 11:00:00.000000'),(63,11,15,5,'IT Manager công ty mua 10 máy này cho nhân viên, chạy ổn định, ít lỗi phần cứng. Hỗ trợ kỹ thuật Lenovo tốt. Sẽ tiếp tục mua thêm.','ACTIVE','2025-05-05 09:00:00.000000','2025-05-05 09:00:00.000000'),(64,16,16,5,'Máy lạnh Inverter tiết kiệm điện rõ rệt, hóa đơn điện giảm 40% so với máy cũ. Làm lạnh nhanh, vận hành im lặng. Lắp đặt chuyên nghiệp, đúng hẹn.','ACTIVE','2025-02-10 09:00:00.000000','2025-02-10 09:00:00.000000'),(65,3,16,4,'Máy lạnh tốt, làm lạnh nhanh. Điều khiển thông minh kết nối wifi tiện. Chỉ tiếc giá hơi cao hơn Panasonic nhưng Daikin nổi tiếng bền.','ACTIVE','2025-03-05 10:00:00.000000','2025-03-05 10:00:00.000000'),(66,9,16,5,'Phòng 20m2 dùng 1.5HP vừa đủ mát. Tính năng tự làm sạch lọc bụi rất hay, không cần vệ sinh thường xuyên. Bảo hành 2 năm an tâm.','ACTIVE','2025-04-01 11:00:00.000000','2025-04-01 11:00:00.000000'),(67,12,17,4,'Màu sắc QLED rực rỡ hơn OLED thường khi xem ban ngày. Tizen OS mượt, Netflix 4K rất đẹp. Chỉ tiếc âm thanh built-in hơi yếu, nên mua thêm soundbar.','ACTIVE','2025-04-15 09:00:00.000000','2025-04-15 09:00:00.000000'),(68,5,17,5,'Tivi đẹp, xem bóng đá 4K rất sướng. Smart TV Tizen có đủ ứng dụng: Netflix, YouTube, FPT Play. Remote Motion Sensing tiện. Giao hàng cẩn thận, lắp đặt tốt.','ACTIVE','2025-04-20 10:00:00.000000','2025-04-20 10:00:00.000000'),(69,20,17,4,'Chất lượng hình ảnh rất tốt, màu sắc tươi sáng. HDR10+ hỗ trợ tốt. Game Mode giảm input lag tốt khi chơi PS5. Giá hợp lý cho 55 inch 4K QLED.','ACTIVE','2025-05-05 11:00:00.000000','2025-05-05 11:00:00.000000'),(70,2,17,5,'Mua thay TV cũ 10 năm, chất lượng vượt xa mong đợi. Cài app FPT Play, K+ xem trực tiếp bóng đá rất mượt. Sẽ tiếp tục tin dùng Samsung.','ACTIVE','2025-05-10 09:00:00.000000','2025-05-10 09:00:00.000000'),(71,4,18,5,'ANC thế hệ 2 lọc tiếng ồn cực tốt, đi máy bay yên tĩnh tuyệt đối. Spatial Audio nghe nhạc như đang trong rạp. Fit tai tốt, không đau dù đeo 4 tiếng.','ACTIVE','2025-02-20 09:00:00.000000','2025-02-20 09:00:00.000000'),(72,10,18,5,'Dùng với iPhone 17 tích hợp hoàn hảo. Tự động chuyển thiết bị Apple rất tiện. ANC tốt nhất trong các tai nghe TWS tôi từng dùng.','ACTIVE','2025-03-10 10:00:00.000000','2025-03-10 10:00:00.000000'),(73,15,18,5,'Chất lượng âm thanh tốt, bass rõ treble sắc. ANC hiệu quả trong văn phòng ồn. Hộp sạc MagSafe tiện khi có iPhone. Đây là tai nghe tôi mua đi mua lại.','ACTIVE','2025-03-25 11:00:00.000000','2025-03-25 11:00:00.000000'),(74,8,18,4,'ANC rất tốt nhưng Transparency Mode đôi khi hơi lạo xạo. Pin 6 giờ hơi ít nhưng hộp sạc 30 giờ bù đắp. Giá 6 triệu xứng đáng cho chất lượng này.','ACTIVE','2025-04-10 09:00:00.000000','2025-04-10 09:00:00.000000'),(75,2,18,5,'Mua lần 2, đợt trước mất 1 bên. Chất lượng vẫn giữ nguyên, ANC cải thiện nhiều so với gen 1. Không thể dùng tai nghe khác sau khi đã quen AirPods Pro.','ACTIVE','2025-05-01 10:00:00.000000','2025-05-01 10:00:00.000000'),(76,18,19,4,'Thiết kế mỏng 7.4mm cầm rất sang. Màn hình AMOLED sáng đẹp. AI Portrait chụp selfie đẹp. Chỉ chip Dimensity 9200+ hơi tụt hậu so với Snap 8 Elite.','ACTIVE','2025-03-20 09:00:00.000000','2025-03-20 09:00:00.000000'),(77,13,19,4,'Camera selfie AI của OPPO rất đẹp, skin tone tự nhiên. SUPERVOOC 80W sạc nhanh ấn tượng. Phù hợp với người thích thiết kế đẹp hơn là hiệu năng thuần túy.','ACTIVE','2025-04-05 10:00:00.000000','2025-04-05 10:00:00.000000'),(78,6,19,5,'Tầm 14 triệu mà thiết kế đẹp như điện thoại cao cấp, pin 5000mAh dùng lâu, sạc 80W nhanh. Đây là lựa chọn tốt cho người thích OPPO.','ACTIVE','2025-04-25 11:00:00.000000','2025-04-25 11:00:00.000000'),(79,8,20,4,'Ốp chính hãng Apple nên chất lượng rất tốt, silicon mềm không nhám tay, lót nhung bên trong tránh xước máy. MagSafe bắt rất chặt, không lo rơi khi sạc.','ACTIVE','2025-04-20 09:00:00.000000','2025-04-20 09:00:00.000000'),(80,20,20,5,'Ốp vừa khít iPhone 17 Pro, không che lệch camera. Màu đen nhìn sang, không bám vân tay. Giá hơi cao so với ốp thường nhưng xứng đáng vì là hàng Apple chính hãng.','ACTIVE','2025-05-05 10:00:00.000000','2025-05-05 10:00:00.000000');
