INSERT INTO `products` VALUES (2,'iPhone 17 Pro','iphone-17-pro','iPhone 17 Pro sở hữu chip Apple A18 Pro hiệu năng vượt trội, màn hình ProMotion 6.3 inch 120Hz, hệ thống camera Pro với cảm biến 50MP, quay video 4K120fps Dolby Vision. Khung Titanium cao cấp, chống nước IP68.',1,4.8,4,5,'2025-04-01 08:00:00.000000','2026-06-04 15:32:48.834063'),(3,'iPhone 17 Pro Max','iphone-17-pro-max','iPhone 17 Pro Max – đỉnh cao dòng iPhone với màn hình 6.9 inch ProMotion 120Hz, chip A18 Pro, pin 4685mAh siêu bền, camera telephoto 5x periscope 50MP. Hoàn hảo cho nhiếp ảnh và quay phim chuyên nghiệp.',1,4.9,5,5,'2025-04-01 08:00:00.000000','2026-06-04 15:32:33.204068'),(5,'iPhone 16 Plus','iphone-16-plus','iPhone 16 Plus màn hình lớn 6.7 inch, pin trâu nhất dòng iPhone 16, chip A18 mạnh mẽ, hỗ trợ Apple Intelligence. Lý tưởng cho người dùng cần màn hình lớn và thời lượng pin dài.',1,4.5,3,5,'2025-01-10 08:00:00.000000','2026-06-04 15:30:48.122167'),(6,'Samsung Galaxy S25','samsung-galaxy-s25','Samsung Galaxy S25 trang bị chip Snapdragon 8 Elite, màn hình Dynamic AMOLED 6.2 inch 120Hz, camera 50MP, RAM 12GB. Hỗ trợ Galaxy AI với nhiều tính năng AI thông minh.',1,4.6,5,6,'2025-02-01 08:00:00.000000','2026-06-04 15:32:11.759369'),(7,'Samsung Galaxy S25 Ultra','samsung-galaxy-s25-ultra','Samsung Galaxy S25 Ultra với bút S Pen tích hợp, màn hình 6.9 inch QHD+ 120Hz, camera 200MP, chip Snapdragon 8 Elite, RAM 12GB. Sản phẩm flagship cao cấp nhất của Samsung.',1,4.8,4,6,'2025-02-01 08:00:00.000000','2026-06-04 15:32:02.240801'),(8,'Samsung Galaxy A55 5G','samsung-galaxy-a55-5g','Samsung Galaxy A55 5G với thiết kế cao cấp, màn hình Super AMOLED 6.6 inch 120Hz, camera 50MP OIS, chip Exynos 1480, pin 5000mAh sạc nhanh 45W. Lựa chọn tầm trung tốt nhất.',1,4.4,5,6,'2025-01-15 08:00:00.000000','2026-06-04 15:31:52.774139'),(9,'Xiaomi 15T','xiaomi-15t','Xiaomi 15T được trang bị chip Snapdragon 8 Elite, màn hình AMOLED 6.36 inch 144Hz, camera Leica 50MP, pin 5400mAh sạc nhanh 90W. Thiết kế mỏng nhẹ, kính cường lực Gorilla Glass Victus 2.',1,4.7,3,7,'2025-03-01 08:00:00.000000','2026-06-04 16:07:59.691719'),(10,'Redmi Note 14 Pro+ 5G','redmi-note-14-pro-plus-5g','Redmi Note 14 Pro+ 5G với màn hình AMOLED 6.67 inch 144Hz, camera 200MP, chip Dimensity 9300+, pin 6000mAh sạc siêu nhanh 120W. Phân khúc tầm trung khủng nhất.',1,4.5,4,7,'2025-02-15 08:00:00.000000','2026-06-04 15:31:17.725483'),(11,'MacBook Air 13 inch M3','macbook-air-13-m3','MacBook Air M3 với chip Apple M3 thế hệ mới, màn hình Liquid Retina 13.6 inch, pin lên đến 18 giờ, thiết kế siêu mỏng nhẹ chỉ 1.24kg. Không quạt, hoạt động hoàn toàn im lặng.',1,4.8,5,9,'2025-01-20 08:00:00.000000','2025-01-20 08:00:00.000000'),(12,'MacBook Pro 14 inch M4','macbook-pro-14-m4','MacBook Pro 14 inch M4 với chip M4 Pro siêu mạnh, màn hình Liquid Retina XDR 14.2 inch ProMotion 120Hz, pin 22 giờ. Dành cho dân sáng tạo nội dung chuyên nghiệp.',1,4.9,4,9,'2025-03-10 08:00:00.000000','2026-06-04 15:47:38.898022'),(13,'Dell XPS 13 Plus 9320','dell-xps-13-plus-9320','Dell XPS 13 Plus với thiết kế siêu mỏng cao cấp, màn hình OLED 13.4 inch 4K, chip Intel Core i7-1360P, RAM 16GB, SSD 512GB. Laptop doanh nhân đẳng cấp hàng đầu.',1,4.6,3,10,'2025-01-25 08:00:00.000000','2025-01-25 08:00:00.000000'),(14,'ASUS ROG Zephyrus G14 2024','asus-rog-zephyrus-g14-2024','ASUS ROG Zephyrus G14 2024 với AMD Ryzen 9 8945HS, GPU NVIDIA RTX 4070, màn hình OLED 14 inch 165Hz, RAM 16GB, SSD 1TB. Laptop gaming mỏng nhẹ hiệu năng đỉnh cao.',1,4.7,5,11,'2025-02-05 08:00:00.000000','2025-02-05 08:00:00.000000'),(15,'Lenovo ThinkPad X1 Carbon Gen 12','lenovo-thinkpad-x1-carbon-gen-12','Lenovo ThinkPad X1 Carbon Gen 12 siêu nhẹ chỉ 1.12kg, chip Intel Core Ultra 7, màn hình 14 inch IPS 2.8K, RAM 32GB, bảo mật vân tay và nhận dạng khuôn mặt. Laptop doanh nhân bền bỉ.',1,4.7,4,12,'2025-02-10 08:00:00.000000','2025-02-10 08:00:00.000000'),(16,'Máy Lạnh Daikin Inverter FTKB35XVMV 1.5 HP','may-lanh-daikin-ftkb35xvmv','Máy lạnh Daikin Inverter 1.5 HP, công suất 12000 BTU, công nghệ Inverter tiết kiệm điện đến 60%, làm lạnh nhanh, lọc bụi và khử mùi hiệu quả. Bảo hành chính hãng 2 năm.',1,4.6,3,13,'2025-01-05 08:00:00.000000','2025-01-05 08:00:00.000000'),(17,'Smart TV Samsung QLED 4K 55 inch QA55Q70C','smart-tv-samsung-qled-55-q70c','Samsung QLED 55 inch 4K, công nghệ Quantum Dot hiển thị màu sắc sống động, Tizen OS thông minh, âm thanh Dolby Atmos 2.2.2CH 60W, kết nối đầy đủ HDMI 2.1, WiFi 5.',1,4.5,4,14,'2025-01-08 08:00:00.000000','2025-01-08 08:00:00.000000'),(18,'Apple AirPods Pro 2','apple-airpods-pro-2','AirPods Pro thế hệ 2 với chip H2, chống ồn ANC thế hệ mới giảm tiếng ồn đến 2 lần so với đời trước, âm thanh không gian Spatial Audio, pin nghe đến 6 giờ, hộp sạc 30 giờ.',1,4.8,5,16,'2025-01-12 08:00:00.000000','2025-01-12 08:00:00.000000'),(19,'OPPO Reno 12 Pro 5G','oppo-reno-12-pro-5g','OPPO Reno 12 Pro 5G với chip MediaTek Dimensity 9200+, màn hình AMOLED 6.7 inch 120Hz, camera 50MP, pin 5000mAh sạc SUPERVOOC 80W. Thiết kế sang trọng mỏng 7.4mm.',1,4.4,3,8,'2025-02-20 08:00:00.000000','2025-02-20 08:00:00.000000'),(20,'Ốp Lưng Apple MagSafe cho iPhone 17 Pro','op-lung-apple-magsafe-iphone-17-pro','Ốp lưng chính hãng Apple cho iPhone 17 Pro, tích hợp MagSafe sạc không dây và gắn phụ kiện, chất liệu silicon cao cấp bảo vệ 4 góc, mặt trong lót nhung mềm tránh trầy.',1,4.5,2,17,'2025-04-05 08:00:00.000000','2025-04-05 08:00:00.000000'),(21,'a','a','a',1,NULL,NULL,NULL,'2026-05-23 17:34:01.606992','2026-05-23 17:34:01.606992');
